// MARK: - App Delegate (Universal Links)

final class AppDelegate: NSObject, UIApplicationDelegate {
    func application(_ application: UIApplication,
                     continue userActivity: NSUserActivity,
                     restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else { return false }

        AppRouter.shared.handleIncomingURL(url)
        return true
    }
}

// MARK: - Routing

final class AppRouter: ObservableObject {
    static let shared = AppRouter()

    enum Route: Equatable {
        case home
        case resetPassword(token: String)
    }

    @Published var route: Route = .home

    func handleIncomingURL(_ url: URL) {
        guard let deepLink = DeepLinkParser.parse(url) else { return }
        switch deepLink {
        case .resetPassword(let token):
            DispatchQueue.main.async {
                self.route = .resetPassword(token: token)
            }
        }
    }

    func resetToHome() {
        route = .home
    }
}

// MARK: - Deep Link Parsing

enum DeepLink: Equatable {
    case resetPassword(token: String)
}

enum DeepLinkParser {
    static func parse(_ url: URL) -> DeepLink? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else { return nil }

        let host = (components.host ?? "").lowercased()
        guard host == "myapp.com" else { return nil }

        let path = components.path.lowercased()

        guard path == "/reset-password" else { return nil }

        let token = components.queryItems?.first(where: { $0.name.lowercased() == "token" })?.value ?? ""
        guard !token.isEmpty else { return nil }

        return .resetPassword(token: token)
    }
}

